1	/**
2	 * Current Vulnerabilities Table Component
3	 *
4	 * Displays current vulnerabilities with filtering, sorting, and pagination capabilities
5	 *
6	 * Features:
7	 * - Filter by severity, system, exception status, and overdue status
8	 * - Sortable columns including overdue status
9	 * - Exception and overdue status badges with tooltips
10	 * - Pagination (50 items per page)
11	 * - Loading and error states
12	 *
13	 * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
14	 * Related to: Feature 021-vulnerability-overdue-exception-logic
15	 */
16	
17	import React, { useState, useEffect, useRef } from "react";
18	import {
19	  getCurrentVulnerabilities,
20	  cleanupDuplicateVulnerabilities,
21	  getDistinctProducts,
22	  getDistinctAdDomains,
23	  getDistinctCloudAccountIds,
24	  exportVulnerabilitiesServerSide,
25	  cancelExportJob,
26	  resetStuckExportJobs,
27	  describeExportStage,
28	  type CurrentVulnerability,
29	  type PaginatedVulnerabilitiesResponse,
30	  type VulnerabilityCleanupResult,
31	  type ExportJob,
32	  type ExportProgressUpdate,
33	} from "../services/vulnerabilityManagementService";
34	import OverdueStatusBadge from "./OverdueStatusBadge";
35	import ExceptionRequestModal from "./ExceptionRequestModal";
36	import CveLink from "./CveLink";
37	import { isAdmin, hasRole, hasVulnAccess } from "../utils/auth";
38	import SearchableSelect from "./SearchableSelect";
39	
40	function formatDuration(totalSec: number): string {
41	  if (totalSec < 60) return `${totalSec}s`;
42	  const m = Math.floor(totalSec / 60);
43	  const s = totalSec % 60;
44	  if (m < 60) return s > 0 ? `${m}m ${s}s` : `${m}m`;
45	  const h = Math.floor(m / 60);
46	  const mr = m % 60;
47	  return mr > 0 ? `${h}h ${mr}m` : `${h}h`;
48	}
49	
50	const CurrentVulnerabilitiesTable: React.FC = () => {
51	  const [paginatedResponse, setPaginatedResponse] =
52	    useState<PaginatedVulnerabilitiesResponse | null>(null);
53	  const [loading, setLoading] = useState(true);
54	  const [error, setError] = useState<string | null>(null);
55	  const [successMessage, setSuccessMessage] = useState<string | null>(null);
56	  const [hasAccess, setHasAccess] = useState(false);
57	
58	  // Exception request modal state
59	  const [showRequestModal, setShowRequestModal] = useState(false);
60	  const [selectedVulnerability, setSelectedVulnerability] =
61	    useState<CurrentVulnerability | null>(null);
62	
63	  // Cleanup modal state
64	  const [showCleanupModal, setShowCleanupModal] = useState(false);
65	  const [cleanupResult, setCleanupResult] =
66	    useState<VulnerabilityCleanupResult | null>(null);
67	  const [cleanupLoading, setCleanupLoading] = useState(false);
68	
69	  // Export state
70	  const [exportLoading, setExportLoading] = useState(false);
71	  const [exportProgress, setExportProgress] = useState<ExportJob | null>(null);
72	  const [exportJobId, setExportJobId] = useState<string | null>(null);
73	  const [exportUpdate, setExportUpdate] = useState<ExportProgressUpdate | null>(null);
74	  const [exportStallWarning, setExportStallWarning] = useState<string | null>(null);
75	
76	  // Filter states
77	  const [severityFilter, setSeverityFilter] = useState<string>("");
78	  const [systemFilter, setSystemFilter] = useState<string>("");
79	  const [debouncedSystemFilter, setDebouncedSystemFilter] = useState<string>("");
80	  const systemFilterTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
81	  const [exceptionFilter, setExceptionFilter] = useState<string>("not_excepted");
82	  const [productFilter, setProductFilter] = useState<string>("");
83	  const [adDomainFilter, setAdDomainFilter] = useState<string>("");
84	  const [cloudAccountIdFilter, setCloudAccountIdFilter] = useState<string>("");
85	
86	  // Available filter options (lazy-loaded)
87	  const [availableProducts, setAvailableProducts] = useState<string[]>([]);
88	  const [availableAdDomains, setAvailableAdDomains] = useState<string[]>([]);
89	  const [availableCloudAccountIds, setAvailableCloudAccountIds] = useState<
90	    string[]
91	  >([]);
92	  const [productsLoaded, setProductsLoaded] = useState(false);
93	  const [adDomainsLoaded, setAdDomainsLoaded] = useState(false);
94	  const [cloudAccountIdsLoaded, setCloudAccountIdsLoaded] = useState(false);
95	
96	  // Pagination states
97	  const [currentPage, setCurrentPage] = useState<number>(0);
98	  const [pageSize] = useState<number>(50);
99	
100	  // Sort states
101	  const [sortField, setSortField] =
102	    useState<keyof CurrentVulnerability>("scanTimestamp");
103	  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");
104	
105	  // Track previous filter values to detect filter-only vs page/sort changes
106	  // When only page/sort changes, we pass knownTotal to skip the expensive count query
107	  const prevFiltersRef = useRef<string>("");
108	
109	  // Cleanup debounce timeout on unmount
110	  useEffect(() => {
111	    return () => {
112	      if (systemFilterTimeoutRef.current) {
113	        clearTimeout(systemFilterTimeoutRef.current);
114	      }
115	    };
116	  }, []);
117	
118	  // Check access on mount - ADMIN, VULN, or SECCHAMPION
119	  useEffect(() => {
120	    const checkAccess = () => {
121	      const isAuthorized = hasVulnAccess();
122	      setHasAccess(isAuthorized);
123	      setLoading(false);
124	
125	      if (!isAuthorized) {
126	        setError(
127	          "Access denied. This page is only accessible to ADMIN, VULN, and SECCHAMPION roles.",
128	        );
129	      }
130	    };
131	
132	    checkAccess();
133	
134	    // Listen for user data updates
135	    window.addEventListener("userLoaded", checkAccess);
136	    return () => window.removeEventListener("userLoaded", checkAccess);
137	  }, []);
138	
139	  useEffect(() => {
140	    if (hasAccess) {
141	      fetchVulnerabilities();
142	    }
143	  }, [
144	    severityFilter,
145	    debouncedSystemFilter,
146	    exceptionFilter,
147	    productFilter,
148	    adDomainFilter,
149	    cloudAccountIdFilter,
150	    currentPage,
151	    sortField,
152	    sortOrder,
153	    hasAccess,
154	  ]);
155	
156	  // Lazy-load filter options: load on first focus instead of on mount
157	  const loadProducts = async () => {
158	    if (productsLoaded || !hasAccess) return;
159	    try {
160	      const products = await getDistinctProducts(undefined, 1000);
161	      setAvailableProducts(products);
162	      setProductsLoaded(true);
163	    } catch (err) {
164	      console.error("Failed to fetch products:", err);
165	    }
166	  };
167	
168	  const loadAdDomains = async () => {
169	    if (adDomainsLoaded || !hasAccess) return;
170	    try {
171	      const domains = await getDistinctAdDomains();
172	      setAvailableAdDomains(domains);
173	      setAdDomainsLoaded(true);
174	    } catch (err) {
175	      console.error("Failed to fetch AD domains:", err);
176	    }
177	  };
178	
179	  const loadCloudAccountIds = async () => {
180	    if (cloudAccountIdsLoaded || !hasAccess) return;
181	    try {
182	      const accountIds = await getDistinctCloudAccountIds();
183	      setAvailableCloudAccountIds(accountIds);
184	      setCloudAccountIdsLoaded(true);
185	    } catch (err) {
186	      console.error("Failed to fetch cloud account IDs:", err);
187	    }
188	  };
189	
190	  const fetchVulnerabilities = async () => {
191	    try {
192	      setLoading(true);
193	      // Map frontend field names to backend sort field names.
194	      // Note: the Overdue Status column is intentionally not sortable — the previous
195	      // scanTimestamp proxy was misleading because it did not reflect the badge value.
196	      const sortFieldMap: Record<string, string> = {
197	        assetName: "assetName",
198	        assetIp: "assetIp",
199	        vulnerabilityId: "vulnerabilityId",
200	        cvssSeverity: "cvssSeverity",
201	        vulnerableProductVersions: "vulnerableProductVersions",
202	        daysOpen: "scanTimestamp",
203	        scanTimestamp: "scanTimestamp",
204	      };
205	      const backendSortField = sortFieldMap[sortField] || undefined;
206	      // Invert sort direction for daysOpen: ascending days = descending scanTimestamp
207	      const effectiveSortOrder = sortField === "daysOpen"
208	        ? (sortOrder === "asc" ? "desc" : "asc")
209	        : sortOrder;
210	
211	      // PERFORMANCE: When only page/sort changes (filters unchanged), pass the known total
212	      // to skip the expensive COUNT query with NOT EXISTS on 358k+ rows
213	      const currentFilterKey = `${severityFilter}|${debouncedSystemFilter}|${exceptionFilter}|${productFilter}|${adDomainFilter}|${cloudAccountIdFilter}`;
214	      const filtersUnchanged = currentFilterKey === prevFiltersRef.current;
215	      const knownTotal = filtersUnchanged && paginatedResponse
216	        ? paginatedResponse.totalElements
217	        : undefined;
218	      prevFiltersRef.current = currentFilterKey;
219	
220	      const data = await getCurrentVulnerabilities(
221	        severityFilter || undefined,
222	        debouncedSystemFilter || undefined,
223	        exceptionFilter || undefined,
224	        productFilter || undefined,
225	        adDomainFilter || undefined,
226	        cloudAccountIdFilter || undefined,
227	        currentPage,
228	        pageSize,
229	        backendSortField,
230	        effectiveSortOrder,
231	        knownTotal,
232	      );
233	      setPaginatedResponse(data);
234	      setError(null);
235	    } catch (err) {
236	      setError(
237	        err instanceof Error ? err.message : "Failed to fetch vulnerabilities",
238	      );
239	    } finally {
240	      setLoading(false);
241	    }
242	  };
243	
244	  const handleFilterChange = () => {
245	    // Reset to first page when filters change
246	    setCurrentPage(0);
247	  };
248	
249	  const handleRequestException = (vuln: CurrentVulnerability) => {
250	    setSelectedVulnerability(vuln);
251	    setShowRequestModal(true);
252	  };
253	
254	  const handleModalClose = () => {
255	    setShowRequestModal(false);
256	    setSelectedVulnerability(null);
257	  };
258	
259	  const handleRequestSuccess = () => {
260	    setSuccessMessage(
261	      "Exception request submitted successfully! Your request is pending review.",
262	    );
263	
264	    // Auto-dismiss success message after 5 seconds
265	    setTimeout(() => {
266	      setSuccessMessage(null);
267	    }, 5000);
268	
269	    // Refresh the vulnerability list
270	    fetchVulnerabilities();
271	  };
272	
273	  const handleCleanupDuplicates = async () => {
274	    try {
275	      setCleanupLoading(true);
276	      const result = await cleanupDuplicateVulnerabilities();
277	      setCleanupResult(result);
278	      setShowCleanupModal(true);
279	
280	      // Refresh the vulnerability list after cleanup
281	      fetchVulnerabilities();
282	    } catch (err) {
283	      setError(
284	        err instanceof Error ? err.message : "Failed to cleanup duplicates",
285	      );
286	    } finally {
287	      setCleanupLoading(false);
288	    }
289	  };
290	
291	  const handleCloseCleanupModal = () => {
292	    setShowCleanupModal(false);
293	    setCleanupResult(null);
294	  };
295	
296	  /**
297	   * Handle export of vulnerabilities to Excel
298	   * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
299	   *
300	   * Uses background job pattern with progress tracking:
301	   * - Starts export job asynchronously
302	   * - Polls for progress (updates UI every 2 seconds)
303	   * - Downloads file when complete
304	   * - Supports cancellation
305	   */
306	  const handleExport = async () => {
307	    try {
308	      setExportLoading(true);
309	      setExportProgress(null);
310	      setExportUpdate(null);
311	      setExportStallWarning(null);
312	      setError(null);
313	
314	      await exportVulnerabilitiesServerSide({
315	        onProgress: (update) => {
316	          setExportProgress(update.job);
317	          setExportJobId(update.job.jobId);
318	          setExportUpdate(update);
319	          // Stall warning auto-clears when progress resumes; the service
320	          // resets stalledSec to 0 on the next poll after progress moves.
321	          if (update.stalledSec < 60) {
322	            setExportStallWarning(null);
323	          }
324	        },
325	        onStall: (update) => {
326	          const stage = describeExportStage(update.job);
327	          setExportStallWarning(
328	            `No progress for ${update.stalledSec}s at stage "${stage}". The export may still be running; you can wait or cancel.`,
329	          );
330	        },
331	      });
332	
333	      setSuccessMessage("Export completed successfully!");
334	      setTimeout(() => setSuccessMessage(null), 5000);
335	    } catch (err) {
336	      setError(
337	        err instanceof Error ? err.message : "Failed to export vulnerabilities",
338	      );
339	    } finally {
340	      setExportLoading(false);
341	      setExportProgress(null);
342	      setExportUpdate(null);
343	      setExportStallWarning(null);
344	      setExportJobId(null);
345	    }
346	  };
347	
348	  /**
349	   * Handle cancellation of running export
350	   */
351	  const handleCancelExport = async () => {
352	    if (!exportJobId) return;
353	
354	    try {
355	      await cancelExportJob(exportJobId);
356	      setExportLoading(false);
357	      setExportProgress(null);
358	      setExportJobId(null);
359	      setSuccessMessage("Export cancelled");
360	      setTimeout(() => setSuccessMessage(null), 3000);
361	    } catch (err) {
362	      setError(
363	        err instanceof Error ? err.message : "Failed to cancel export",
364	      );
365	    }
366	  };
367	
368	  /**
369	   * Handle reset of stuck export jobs
370	   * Called when user encounters "already have an export in progress" error
371	   */
372	  const handleResetStuckExports = async () => {
373	    try {
374	      setExportLoading(true);
375	      const result = await resetStuckExportJobs();
376	      setSuccessMessage(result.message);
377	      setTimeout(() => setSuccessMessage(null), 5000);
378	      setError(null);
379	    } catch (err) {
380	      setError(
381	        err instanceof Error ? err.message : "Failed to reset stuck exports",
382	      );
383	    } finally {
384	      setExportLoading(false);
385	    }
386	  };
387	
388	  const handleSort = (field: keyof CurrentVulnerability) => {
389	    if (sortField === field) {
390	      setSortOrder(sortOrder === "asc" ? "desc" : "asc");
391	    } else {
392	      setSortField(field);
393	      setSortOrder("asc");
394	    }
395	    setCurrentPage(0); // Reset to first page on sort change
396	  };
397	
398	  const getSortedVulnerabilities = () => {
399	    if (
400	      !paginatedResponse ||
401	      !paginatedResponse.content ||
402	      !Array.isArray(paginatedResponse.content)
403	    ) {
404	      return [];
405	    }
406	    // Sorting is now server-side, return content as-is
407	    return paginatedResponse.content;
408	  };
409	
410	  const getSeverityBadgeClass = (severity: string | null): string => {
411	    if (!severity) return "scand-neutral";
412	    const sev = severity.toLowerCase();
413	    if (sev.includes("critical")) return "scand-critical";
414	    if (sev.includes("high")) return "scand-high";
415	    if (sev.includes("medium")) return "scand-medium";
416	    if (sev.includes("low")) return "scand-low";
417	    return "scand-neutral";
418	  };
419	
420	  const getExceptionBadge = (hasException: boolean, reason: string | null) => {
421	    if (hasException) {
422	      return (
423	        <span
424	          className="badge bg-success"
425	          title={reason || "This vulnerability is excepted"}
426	        >
427	          Excepted
428	        </span>
429	      );
430	    }
431	    return (
432	      <span className="badge bg-danger" title="No active exception">
433	        Not Excepted
434	      </span>
435	    );
436	  };
437	
438	  const SortIcon: React.FC<{ field: keyof CurrentVulnerability }> = ({
439	    field,
440	  }) => {
441	    if (sortField !== field)
442	      return <i className="bi bi-chevron-expand ms-1 text-muted"></i>;
443	    return sortOrder === "asc" ? (
444	      <i className="bi bi-chevron-up ms-1"></i>
445	    ) : (
446	      <i className="bi bi-chevron-down ms-1"></i>
447	    );
448	  };
449	
450	  const handlePageChange = (newPage: number) => {
451	    setCurrentPage(newPage);
452	    window.scrollTo({ top: 0, behavior: "smooth" });
453	  };
454	
455	  const renderPagination = () => {
456	    if (!paginatedResponse || paginatedResponse.totalPages <= 1) return null;
457	
458	    const { currentPage, totalPages, hasPrevious, hasNext, totalElements } =
459	      paginatedResponse;
460	    const startItem = currentPage * pageSize + 1;
461	    const endItem = Math.min((currentPage + 1) * pageSize, totalElements);
462	
463	    // Generate page numbers to show
464	    const maxPagesToShow = 7;
465	    let startPage = Math.max(0, currentPage - Math.floor(maxPagesToShow / 2));
466	    let endPage = Math.min(totalPages - 1, startPage + maxPagesToShow - 1);
467	
468	    // Adjust if we're near the end
469	    if (endPage - startPage < maxPagesToShow - 1) {
470	      startPage = Math.max(0, endPage - maxPagesToShow + 1);
471	    }
472	
473	    const pageNumbers = [];
474	    for (let i = startPage; i <= endPage; i++) {
475	      pageNumbers.push(i);
476	    }
477	
478	    return (
479	      <div className="d-flex justify-content-between align-items-center mt-4">
480	        <div className="text-muted">
481	          Showing {startItem} to {endItem} of {totalElements} vulnerabilities
482	        </div>
483	        <nav aria-label="Vulnerability pagination">
484	          <ul className="pagination mb-0">
485	            <li className={`page-item ${!hasPrevious ? "disabled" : ""}`}>
486	              <button
487	                className="page-link"
488	                onClick={() => handlePageChange(currentPage - 1)}
489	                disabled={!hasPrevious}
490	                aria-label="Previous"
491	              >
492	                <span aria-hidden="true">&laquo;</span>
493	              </button>
494	            </li>
495	
496	            {startPage > 0 && (
497	              <>
498	                <li className="page-item">
499	                  <button
500	                    className="page-link"
501	                    onClick={() => handlePageChange(0)}
502	                  >
503	                    1
504	                  </button>
505	                </li>
506	                {startPage > 1 && (
507	                  <li className="page-item disabled">
508	                    <span className="page-link">...</span>
509	                  </li>
510	                )}
511	              </>
512	            )}
513	
514	            {pageNumbers.map((pageNum) => (
515	              <li
516	                key={pageNum}
517	                className={`page-item ${currentPage === pageNum ? "active" : ""}`}
518	              >
519	                <button
520	                  className="page-link"
521	                  onClick={() => handlePageChange(pageNum)}
522	                >
523	                  {pageNum + 1}
524	                </button>
525	              </li>
526	            ))}
527	
528	            {endPage < totalPages - 1 && (
529	              <>
530	                {endPage < totalPages - 2 && (
531	                  <li className="page-item disabled">
532	                    <span className="page-link">...</span>
