1213	                    duplicate{cleanupResult.duplicatesRemoved !== 1 ? "s" : ""}!
1214	                  </div>
1215	                )}
1216	              </div>
1217	              <div className="modal-footer">
1218	                <button
1219	                  type="button"
1220	                  className="btn btn-primary"
1221	                  onClick={handleCloseCleanupModal}
1222	                >
1223	                  Close
1224	                </button>
1225	              </div>
1226	            </div>
1227	          </div>
1228	        </div>
1229	      )}
1230	    </div>
1231	  );
