    // by VulnerabilityRepository @Query bodies and the analytics services).
    const val EXCEPTION_EXISTS_SUBQUERY =
        "SELECT 1 FROM vulnerability_exception e WHERE ${com.secman.repository.ExceptionMatchSql.EXCEPTION_MATCH}"
}

@Transactional
open fun getCurrentVulnerabilitiesOptimized(
    accessibleAssetIds: Set<Long>,
    isAdmin: Boolean,
    severity: String?,
    system: String?,
    exceptionStatus: String?,
    product: String?,
    adDomain: String?,
    cloudAccountId: String? = null,
    page: Int,
    size: Int,
    sort: String? = null,
    sortDir: String? = null,
    knownTotal: Long? = null
): com.secman.dto.PaginatedVulnerabilitiesResponse {
    log.debug("Getting current vulnerabilities (optimized) - isAdmin: {}, assetIds: {}, severity: {}, system: {}, exceptionStatus: {}, cloudAccountId: {}, page: {}, size: {}",
        isAdmin, if (isAdmin) "ALL" else accessibleAssetIds.size, severity, system, exceptionStatus, cloudAccountId, page, size)

    // Pre-process filter values: lowercase domain filter since adDomain is stored normalized
    val normalizedDomainFilter = adDomain?.takeIf { it.isNotBlank() }?.lowercase()
    val normalizedCloudAccountIdFilter = cloudAccountId?.takeIf { it.isNotBlank() }
    val normalizedSeverity = severity?.takeIf { it.isNotBlank() }
    val normalizedSystem = system?.takeIf { it.isNotBlank() }
    val normalizedProduct = product?.takeIf { it.isNotBlank() }
    val normalizedExceptionStatus = exceptionStatus?.lowercase()?.replace("-", "_")?.takeIf { it.isNotBlank() }

    // Non-ADMIN: check for empty accessible assets
    if (!isAdmin && accessibleAssetIds.isEmpty()) {
        return com.secman.dto.PaginatedVulnerabilitiesResponse(
            content = emptyList(),
            totalElements = 0,
            totalPages = 0,
            currentPage = page,
            pageSize = size,
            hasNext = false,
            hasPrevious = false
        )
    }

    // Get active exceptions ONCE (cached)
    val activeExceptions = getActiveExceptions()
    log.debug("Found {} active exceptions (from cache)", activeExceptions.size)

    // PERFORMANCE (Feature 073): When exception status filter is set,
    // use SQL-level filtering to avoid loading all 358k rows into memory
    // This now applies to both admin AND non-admin users
    if (!normalizedExceptionStatus.isNullOrBlank()) {
        return if (isAdmin) {
            getCurrentVulnerabilitiesByStatusSql(
                normalizedExceptionStatus, normalizedSeverity, normalizedSystem,
                normalizedProduct, normalizedDomainFilter, normalizedCloudAccountIdFilter,
                activeExceptions, page, size, knownTotal, sort, sortDir
            )
        } else {
            // Feature 073: SQL-level filtering for non-admin users
            getCurrentVulnerabilitiesByStatusSqlWithAccessControl(
                accessibleAssetIds, normalizedExceptionStatus, normalizedSeverity,
                normalizedSystem, normalizedProduct, normalizedDomainFilter,
                normalizedCloudAccountIdFilter, activeExceptions, page, size, knownTotal,
                sort, sortDir
            )
        }
    }

    // Determine if custom sort is requested
    val hasCustomSort = !sort.isNullOrBlank() && SORT_FIELD_MAP.containsKey(sort)
    val pageable = io.micronaut.data.model.Pageable.from(page, size)

    // PERFORMANCE: Use EntityManager with dynamic ORDER BY for custom sorts.
    // The @Query JPQL methods have hardcoded ORDER BY, so Pageable.sort doesn't work with them.
    // Non-admin users now reach this branch too (Phase 2 of the sort fix); accessible-asset
    // filtering is applied inside the helper when accessibleAssetIds is non-null.
    if (hasCustomSort) {
        return getCurrentVulnerabilitiesWithCustomSort(
            normalizedSeverity, normalizedSystem, normalizedProduct,
            normalizedDomainFilter, normalizedCloudAccountIdFilter,
            normalizedExceptionStatus, activeExceptions,
            sort, sortDir, page, size,
            accessibleAssetIds = if (isAdmin) null else accessibleAssetIds
        )
    }

    // Choose query based on admin status (uses default ORDER BY from JPQL)
    // No exception status filter at this point - use standard pagination
    val vulnPage = if (isAdmin) {
        vulnerabilityRepository.findLatestVulnerabilitiesPerAssetWithFilters(
            severity = normalizedSeverity,
            assetName = normalizedSystem,
            productFilter = normalizedProduct,
            domainFilter = normalizedDomainFilter,
            cloudAccountIdFilter = normalizedCloudAccountIdFilter,
            pageable = pageable
        )
    } else {
        vulnerabilityRepository.findLatestVulnerabilitiesWithAccessControl(
            accessibleAssetIds = accessibleAssetIds,
            severity = normalizedSeverity,
            assetName = normalizedSystem,
            productFilter = normalizedProduct,
            domainFilter = normalizedDomainFilter,
            cloudAccountIdFilter = normalizedCloudAccountIdFilter,
            pageable = pageable
        )
    }

    val currentVulns = vulnPage.content
    log.debug("Found {} vulnerabilities from database query", currentVulns.size)

    // Map to DTOs with exception information
    val vulnsWithException = mapToVulnerabilityDtos(currentVulns, activeExceptions)

    // Check if all filters are empty (for cached count optimization)
    val hasNoFilters = normalizedSeverity == null && normalizedSystem == null && normalizedProduct == null
            && normalizedDomainFilter == null && normalizedCloudAccountIdFilter == null

    // No exception filter - use DB pagination metadata
    // PERFORMANCE: Use cached total count for unfiltered admin queries, or knownTotal if provided
    val totalElements = knownTotal ?: if (isAdmin && hasNoFilters) {
        getCachedTotalCount()
    } else {
        vulnPage.totalSize
    }
    val totalPages = if (totalElements > 0) kotlin.math.ceil(totalElements.toDouble() / size).toInt() else 0

    val filteredResult = com.secman.dto.PaginatedVulnerabilitiesResponse(
        content = vulnsWithException,
        totalElements = totalElements,
        totalPages = totalPages,
        currentPage = page,
        pageSize = size,
        hasNext = page < totalPages - 1,
        hasPrevious = page > 0
    )

    log.info("Returning {} current vulnerabilities (page {}/{}, total {})",
        filteredResult.content.size, page + 1, filteredResult.totalPages, filteredResult.totalElements)
    return filteredResult
}

/**
 * SQL-level exception status filtering for admin users
 * Eliminates loading all 358k rows into memory when filtering by overdue/excepted/ok
 */
private fun getCurrentVulnerabilitiesByStatusSql(
    exceptionStatus: String,
    severity: String?,
    system: String?,
    product: String?,
    domainFilter: String?,
    cloudAccountIdFilter: String?,
    activeExceptions: List<VulnerabilityException>,
    page: Int,
    size: Int,
    knownTotal: Long? = null,
    sort: String? = null,
    sortDir: String? = null
): com.secman.dto.PaginatedVulnerabilitiesResponse {
    val reminderOneDays = vulnerabilityConfigService.getReminderOneDays()
    val thresholdDate = LocalDateTime.now().minusDays(reminderOneDays.toLong())
    val pageOffset = page * size

    // Check if all additional filters are empty (for cached count optimization)
    val hasNoAdditionalFilters = severity == null && system == null && product == null
            && domainFilter == null && cloudAccountIdFilter == null

    // When the user has chosen a sort column, route through the dynamic-SQL helper
    // so ORDER BY is honored. Default-sort requests stay on the existing tuned
    // @Query repository methods to preserve their performance characteristics.
    val hasCustomSort = !sort.isNullOrBlank() && SORT_FIELD_MAP_NATIVE.containsKey(sort)

    log.debug("Using SQL-level exception status filter: {} (threshold: {} days, date: {}, skipCount: {}, hasNoAdditionalFilters: {}, customSort: {})",
        exceptionStatus, reminderOneDays, thresholdDate, knownTotal != null, hasNoAdditionalFilters, hasCustomSort)

    if (hasCustomSort) {
        val (vulns, totalCount) = executeStatusFilteredCustomSortQuery(
            statusType = exceptionStatus,
            accessibleAssetIds = null,
            thresholdDate = thresholdDate,
            severity = severity,
            system = system,
            product = product,
            domainFilter = domainFilter,
            cloudAccountIdFilter = cloudAccountIdFilter,
            sort = sort,
            sortDir = sortDir,
            page = page,
            size = size
        )
        val effectiveTotal = knownTotal ?: totalCount
        val totalPages = if (effectiveTotal > 0) kotlin.math.ceil(effectiveTotal.toDouble() / size).toInt() else 0
        return com.secman.dto.PaginatedVulnerabilitiesResponse(
            content = mapToVulnerabilityDtos(vulns, activeExceptions),
            totalElements = effectiveTotal,
            totalPages = totalPages,
            currentPage = page,
            pageSize = size,
            hasNext = page < totalPages - 1,
            hasPrevious = page > 0
        )
    }

    val (vulns, totalCount) = when (exceptionStatus) {
        "overdue" -> {
            val data = vulnerabilityRepository.findOverdueVulnerabilitiesAdmin(
                thresholdDate, severity, system, product, domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countOverdueVulnerabilitiesAdmin(
                thresholdDate, severity, system, product, domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        "excepted" -> {
            val data = vulnerabilityRepository.findExceptedVulnerabilitiesAdmin(
                severity, system, product, domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countExceptedVulnerabilitiesAdmin(
                severity, system, product, domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        "ok" -> {
            val data = vulnerabilityRepository.findOkVulnerabilitiesAdmin(
                thresholdDate, severity, system, product, domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countOkVulnerabilitiesAdmin(
                thresholdDate, severity, system, product, domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        "not_excepted" -> {
            val data = vulnerabilityRepository.findNotExceptedVulnerabilitiesAdmin(
                severity, system, product, domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            // PERFORMANCE: Use cached count for unfiltered not_excepted admin queries
            // This is the most expensive query (COUNT with NOT EXISTS on 358k+ rows)
            val count = knownTotal ?: if (hasNoAdditionalFilters) {
                getCachedNotExceptedCountAdmin()
            } else {
                vulnerabilityRepository.countNotExceptedVulnerabilitiesAdmin(
                    severity, system, product, domainFilter, cloudAccountIdFilter
                )
            }
            Pair(data, count)
        }
        else -> {
            log.debug("Unsupported SQL exception status '{}', falling back", exceptionStatus)
            return getCurrentVulnerabilitiesOptimized(
                emptySet(), true, severity, system, null, product,
                domainFilter, cloudAccountIdFilter, page, size
            )
        }
    }

    log.debug("SQL status filter returned {} vulns (total: {})", vulns.size, totalCount)

    val vulnsWithException = mapToVulnerabilityDtos(vulns, activeExceptions)
    val totalPages = if (totalCount > 0) kotlin.math.ceil(totalCount.toDouble() / size).toInt() else 0

    return com.secman.dto.PaginatedVulnerabilitiesResponse(
        content = vulnsWithException,
        totalElements = totalCount,
        totalPages = totalPages,
        currentPage = page,
        pageSize = size,
        hasNext = page < totalPages - 1,
        hasPrevious = page > 0
    )
}

/**
 * SQL-level exception status filtering for non-admin users (with access control)
 * Feature: 073-memory-optimization
 *
 * Eliminates loading all data into memory when filtering by overdue/excepted/ok
 * for non-admin users. Access control is pushed to SQL level.
 */
private fun getCurrentVulnerabilitiesByStatusSqlWithAccessControl(
    accessibleAssetIds: Set<Long>,
    exceptionStatus: String,
    severity: String?,
    system: String?,
    product: String?,
    domainFilter: String?,
    cloudAccountIdFilter: String?,
    activeExceptions: List<VulnerabilityException>,
    page: Int,
    size: Int,
    knownTotal: Long? = null,
    sort: String? = null,
    sortDir: String? = null
): com.secman.dto.PaginatedVulnerabilitiesResponse {
    val reminderOneDays = vulnerabilityConfigService.getReminderOneDays()
    val thresholdDate = LocalDateTime.now().minusDays(reminderOneDays.toLong())
    val pageOffset = page * size

    val hasCustomSort = !sort.isNullOrBlank() && SORT_FIELD_MAP_NATIVE.containsKey(sort)

    log.debug("Using SQL-level exception status filter (non-admin): {} (threshold: {} days, assets: {}, skipCount: {}, customSort: {})",
        exceptionStatus, reminderOneDays, accessibleAssetIds.size, knownTotal != null, hasCustomSort)

    if (hasCustomSort) {
        val (vulns, totalCount) = executeStatusFilteredCustomSortQuery(
            statusType = exceptionStatus,
            accessibleAssetIds = accessibleAssetIds,
            thresholdDate = thresholdDate,
            severity = severity,
            system = system,
            product = product,
            domainFilter = domainFilter,
            cloudAccountIdFilter = cloudAccountIdFilter,
            sort = sort,
            sortDir = sortDir,
            page = page,
            size = size
        )
        val effectiveTotal = knownTotal ?: totalCount
        val totalPages = if (effectiveTotal > 0) kotlin.math.ceil(effectiveTotal.toDouble() / size).toInt() else 0
        return com.secman.dto.PaginatedVulnerabilitiesResponse(
            content = mapToVulnerabilityDtos(vulns, activeExceptions),
            totalElements = effectiveTotal,
            totalPages = totalPages,
            currentPage = page,
            pageSize = size,
            hasNext = page < totalPages - 1,
            hasPrevious = page > 0
        )
    }

    val (vulns, totalCount) = when (exceptionStatus) {
        "overdue" -> {
            val data = vulnerabilityRepository.findOverdueVulnerabilitiesWithAccessControl(
                accessibleAssetIds, thresholdDate, severity, system, product,
                domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countOverdueVulnerabilitiesWithAccessControl(
                accessibleAssetIds, thresholdDate, severity, system, product,
                domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        "excepted" -> {
            val data = vulnerabilityRepository.findExceptedVulnerabilitiesWithAccessControl(
                accessibleAssetIds, severity, system, product,
                domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countExceptedVulnerabilitiesWithAccessControl(
                accessibleAssetIds, severity, system, product,
                domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        "ok" -> {
            val data = vulnerabilityRepository.findOkVulnerabilitiesWithAccessControl(
                accessibleAssetIds, thresholdDate, severity, system, product,
                domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countOkVulnerabilitiesWithAccessControl(
                accessibleAssetIds, thresholdDate, severity, system, product,
                domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        "not_excepted" -> {
            val data = vulnerabilityRepository.findNotExceptedVulnerabilitiesWithAccessControl(
                accessibleAssetIds, severity, system, product,
                domainFilter, cloudAccountIdFilter, size, pageOffset
            )
            val count = knownTotal ?: vulnerabilityRepository.countNotExceptedVulnerabilitiesWithAccessControl(
                accessibleAssetIds, severity, system, product,
                domainFilter, cloudAccountIdFilter
            )
            Pair(data, count)
        }
        else -> {
            log.debug("Unsupported SQL exception status '{}' for non-admin, falling back", exceptionStatus)
            return getCurrentVulnerabilitiesOptimized(
                accessibleAssetIds, false, severity, system, null, product,
                domainFilter, cloudAccountIdFilter, page, size
            )
        }
    }

    log.debug("SQL status filter (non-admin) returned {} vulns (total: {})", vulns.size, totalCount)

    val vulnsWithException = mapToVulnerabilityDtos(vulns, activeExceptions)
    val totalPages = if (totalCount > 0) kotlin.math.ceil(totalCount.toDouble() / size).toInt() else 0

    return com.secman.dto.PaginatedVulnerabilitiesResponse(
        content = vulnsWithException,
        totalElements = totalCount,
        totalPages = totalPages,
        currentPage = page,
        pageSize = size,
        hasNext = page < totalPages - 1,

    "cvssSeverity" to SEVERITY_RANK_JPQL,
    "vulnerableProductVersions" to "v.vulnerableProductVersions",
    "daysOpen" to "v.scanTimestamp",
    "scanTimestamp" to "v.scanTimestamp",
    "importTimestamp" to "v.importTimestamp"
)
// Same mapping for native SQL (uses column names)
val SORT_FIELD_MAP_NATIVE = mapOf(
    "assetName" to "a.name",
    "assetIp" to "a.ip",
    "vulnerabilityId" to "v.vulnerability_id",
    "cvssSeverity" to SEVERITY_RANK_NATIVE,
    "vulnerableProductVersions" to "v.vulnerable_product_versions",
    "daysOpen" to "v.scan_timestamp",
    "scanTimestamp" to "v.scan_timestamp",
    "importTimestamp" to "v.import_timestamp"
)

// Default ORDER BY used by the dynamic native-SQL helper when no explicit sort is requested.
// Matches the previously hardcoded ordering of findNotExceptedVulnerabilitiesAdmin et al.
const val DEFAULT_ORDER_BY_NATIVE =
    "v.import_timestamp DESC, a.name ASC, v.vulnerability_id ASC"

// Subquery used by both EXISTS / NOT EXISTS variants of the exception-status check.
// Delegates to ExceptionMatchSql.EXCEPTION_MATCH (the single source of truth shared

/**
 * Run a native-SQL paginated query for the four exception-status filter modes
 * (overdue / excepted / ok / not_excepted) with a user-chosen ORDER BY.
 *
 * Reused by both admin and non-admin code paths: pass null `accessibleAssetIds`
 * for admin (no asset restriction) or a non-empty set for access-controlled users.
 *
 * SECURITY: `sort` is looked up in [SORT_FIELD_MAP_NATIVE] before any string
 * concatenation, so user input never reaches the SQL ORDER BY clause directly.
 * All filter values are bound as parameters.
 */
private fun executeStatusFilteredCustomSortQuery(
    statusType: String,
    accessibleAssetIds: Set<Long>?,
    thresholdDate: LocalDateTime,
    severity: String?,
    system: String?,
    product: String?,
    domainFilter: String?,
    cloudAccountIdFilter: String?,
    sort: String,
    sortDir: String?,
    page: Int,
    size: Int
): Pair<List<Vulnerability>, Long> {
    // SECURITY: Lock the access-control invariant — see getCurrentVulnerabilitiesWithCustomSort
    // for rationale. Empty asset sets are the responsibility of the dispatcher to short-circuit;
    // we fail fast here if that ever drifts.
    require(accessibleAssetIds == null || accessibleAssetIds.isNotEmpty()) {
        "Non-admin status-filtered custom-sort path requires non-empty accessibleAssetIds"
    }

    val sortColumn = SORT_FIELD_MAP_NATIVE[sort]
        ?: throw IllegalArgumentException("Invalid sort field: $sort. Allowed: ${SORT_FIELD_MAP_NATIVE.keys}")
    val direction = if (sortDir?.lowercase() == "asc") "ASC" else "DESC"

    // Status-specific WHERE fragment. Mirrors the existing repository @Query bodies
    // exactly so semantics are unchanged when this helper handles the request.
    val statusClause = when (statusType) {
        "overdue" -> "AND v.scan_timestamp < :thresholdDate AND NOT EXISTS ($EXCEPTION_EXISTS_SUBQUERY)"
        "not_excepted" -> "AND NOT EXISTS ($EXCEPTION_EXISTS_SUBQUERY)"
        "excepted" -> "AND EXISTS ($EXCEPTION_EXISTS_SUBQUERY)"
        // OK historically only excludes overdue rows; it does not check exceptions.
        "ok" -> "AND v.scan_timestamp >= :thresholdDate"
        else -> throw IllegalArgumentException("Unsupported statusType: $statusType")
    }
    val needsThreshold = statusType == "overdue" || statusType == "ok"

    val accessClause = if (accessibleAssetIds != null) {
        "AND a.id IN (:accessibleAssetIds)"
    } else {
        ""
    }

    val filterClauses = StringBuilder().apply {
        if (severity != null) append(" AND v.cvss_severity = :severity")
        if (system != null) append(" AND LOWER(a.name) LIKE LOWER(CONCAT('%', :assetName, '%'))")
        if (product != null) append(" AND LOWER(v.vulnerable_product_versions) LIKE LOWER(CONCAT('%', :productFilter, '%'))")
        if (domainFilter != null) append(" AND a.ad_domain LIKE CONCAT('%', :domainFilter, '%')")
        if (cloudAccountIdFilter != null) append(" AND a.cloud_account_id LIKE CONCAT('%', :cloudAccountIdFilter, '%')")
    }.toString()

    // Stable secondary sort by v.id keeps pagination deterministic when the primary column has ties.
    val orderBy = "ORDER BY $sortColumn $direction, v.id ASC"

    val dataSql = """
        SELECT v.* FROM vulnerability v
        JOIN asset a ON v.asset_id = a.id
        WHERE 1=1
        $accessClause
        $statusClause
        $filterClauses
        $orderBy
        LIMIT :pageSize OFFSET :pageOffset
    """.trimIndent()

    val countSql = """
        SELECT COUNT(*) FROM vulnerability v
        JOIN asset a ON v.asset_id = a.id
        WHERE 1=1
        $accessClause
        $statusClause
        $filterClauses
    """.trimIndent()

    log.debug("Status-filtered custom sort: status={} access={} sort={} {} (data SQL length={})",
        statusType, accessibleAssetIds?.size ?: "ALL", sortColumn, direction, dataSql.length)

    val dataQuery = entityManager.createNativeQuery(dataSql, Vulnerability::class.java)
    val countQuery = entityManager.createNativeQuery(countSql)

    fun bindParams(q: jakarta.persistence.Query) {
        if (accessibleAssetIds != null) q.setParameter("accessibleAssetIds", accessibleAssetIds)
        if (needsThreshold) q.setParameter("thresholdDate", thresholdDate)
        if (severity != null) q.setParameter("severity", severity)
        if (system != null) q.setParameter("assetName", system)
        if (product != null) q.setParameter("productFilter", product)
        if (domainFilter != null) q.setParameter("domainFilter", domainFilter)
        if (cloudAccountIdFilter != null) q.setParameter("cloudAccountIdFilter", cloudAccountIdFilter)
    }

    bindParams(dataQuery)
    dataQuery.setParameter("pageSize", size)
    dataQuery.setParameter("pageOffset", page * size)

    bindParams(countQuery)

    @Suppress("UNCHECKED_CAST")
    val vulns = dataQuery.resultList as List<Vulnerability>
    val totalCount = (countQuery.singleResult as Number).toLong()

    log.info("Status-filtered custom sort returned {} vulns (total: {}, status: {}, sort: {} {})",
        vulns.size, totalCount, statusType, sortColumn, direction)

    return Pair(vulns, totalCount)
}

/**
 * Get distinct product versions from all vulnerabilities
 * Feature 021 Phase 3: For product autocomplete
 *
 * @param searchTerm Optional search term to filter products
 * @param limit Maximum number of results (default: 50)
 * @return List of unique product version strings
 */
fun getDistinctProducts(searchTerm: String? = null, limit: Int = 50): List<String> {
    log.debug("Getting distinct products - searchTerm: {}, limit: {}", searchTerm, limit)

    val allProducts = vulnerabilityRepository.findDistinctProductVersions()

    val filtered = if (!searchTerm.isNullOrBlank()) {
        allProducts.filter { it.contains(searchTerm, ignoreCase = true) }
    } else {
        allProducts
    }

    val limited = filtered.take(limit)
    log.info("Returning {} distinct products", limited.size)
    return limited
}

