/**
 * Map vulnerability entities to DTOs with exception and overdue status information
 */
private fun mapToVulnerabilityDtos(
    vulns: List<Vulnerability>,
    activeExceptions: List<VulnerabilityException>
): List<VulnerabilityWithExceptionDto> {
    return vulns.map { vuln ->
        val overdueInfo = calculateOverdueStatus(vuln, vuln.asset, activeExceptions)
        val matchingException = activeExceptions.firstOrNull { it.matches(vuln, vuln.asset) }

        VulnerabilityWithExceptionDto(
            id = vuln.id,
            asset = vuln.asset,
            assetId = vuln.asset.id!!,
            assetName = vuln.asset.name,
            assetIp = vuln.asset.ip,
            cloudInstanceId = vuln.asset.cloudInstanceId,
            vulnerabilityId = vuln.vulnerabilityId,
            cvssSeverity = vuln.cvssSeverity,
            vulnerableProductVersions = vuln.vulnerableProductVersions,
            daysOpen = vuln.daysOpen,
            scanTimestamp = vuln.scanTimestamp,
            hasException = matchingException != null,
            exceptionReason = matchingException?.reason,
            ageInDays = overdueInfo.ageInDays,
            overdueStatus = overdueInfo.status,
            daysOverdue = overdueInfo.daysOverdue,
            exceptionId = overdueInfo.exceptionId,
            exceptionEndDate = overdueInfo.exceptionEndDate,
            exceptionSubject = matchingException?.subject,
            exceptionScope = matchingException?.scope,
            exceptionScopesAsset = matchingException?.let { isAssetScoped(it) }
        )
    }
}

/**
 * True when the given exception covers one specific asset, false when its
 * scope spans multiple assets. Used by the UI to phrase scope hints.
 */
private fun isAssetScoped(exception: VulnerabilityException): Boolean {
    return when (exception.scope) {
        VulnerabilityException.Scope.IP -> true
        VulnerabilityException.Scope.ASSET -> true
        VulnerabilityException.Scope.GLOBAL -> false
        VulnerabilityException.Scope.AWS_ACCOUNT -> false
    }
}

/**
 * Execute paginated vulnerability query with custom ORDER BY using EntityManager
 * Required because Micronaut Data @Query with JPQL doesn't support dynamic Sort from Pageable
 */
private fun getCurrentVulnerabilitiesWithCustomSort(
    severity: String?,

 * - cloudAccountId: Optional AWS cloud account ID filter (substring match, case-insensitive)
 * - page: Page number (0-indexed, default: 0)
 * - size: Page size (default: 50, max: 500)
 * - sort: Sort field (e.g., "assetName", "cvssSeverity", "scanTimestamp", "vulnerabilityId", "vulnerableProductVersions", "daysOpen")
 * - sortDir: Sort direction ("asc" or "desc", default: "desc")
 */
@Get("/api/vulnerabilities/current")
@Secured("ADMIN", "VULN", "SECCHAMPION")
open fun getCurrentVulnerabilities(
    authentication: Authentication,
    @Nullable @QueryValue severity: String?,
    @Nullable @QueryValue system: String?,
    @Nullable @QueryValue exceptionStatus: String?,
    @Nullable @QueryValue product: String?,
    @Nullable @QueryValue adDomain: String?,
    @Nullable @QueryValue cloudAccountId: String?,
    @Nullable @QueryValue page: Int?,
    @Nullable @QueryValue size: Int?,
    @Nullable @QueryValue sort: String?,
    @Nullable @QueryValue sortDir: String?,
    @Nullable @QueryValue knownTotal: Long?
): HttpResponse<PaginatedVulnerabilitiesResponse> {
    return try {
        // Validate and sanitize pagination parameters.
        // Page is capped at 100_000 to bound the SQL OFFSET cost: an unbounded page
        // value lets a caller force MariaDB into a large sequential scan-and-discard
        // (e.g. ?page=10000000 → OFFSET 5_000_000_000). 100_000 is well past anything
        // legitimate pagination reaches given the table's row count and is cheap to enforce.
        val pageNumber = minOf(maxOf(page ?: 0, 0), 100_000)
        val pageSize = minOf(maxOf(size ?: 50, 1), 500)

        // Default to excluding excepted vulnerabilities when no filter specified
        val effectiveExceptionStatus = if (exceptionStatus.isNullOrBlank()) "not_excepted" else exceptionStatus

        log.debug("Getting current vulnerabilities for user: {} - severity: {}, system: {}, exceptionStatus: {} (effective: {}), product: {}, adDomain: {}, cloudAccountId: {}, page: {}, size: {}",
            authentication.name, severity, system, exceptionStatus, effectiveExceptionStatus, product, adDomain, cloudAccountId, pageNumber, pageSize)

        // Check if user has universal access (ADMIN or SECCHAMPION)
        val isAdmin = authentication.roles.contains("ADMIN") || authentication.roles.contains("SECCHAMPION")

        // Get accessible asset IDs (only needed for non-ADMIN users)
        // PERFORMANCE: For ADMIN users, we skip this query entirely
        val accessibleAssetIds = if (isAdmin) {
            emptySet()  // Not used for ADMIN
        } else {
            assetFilterService.getAccessibleAssets(authentication)
                .mapNotNull { it.id }
                .toSet()
        }

        // PERFORMANCE OPTIMIZED: Use database-level pagination and access control
        // This replaces the old pattern of loading all data and filtering in-memory
        val response = vulnerabilityService.getCurrentVulnerabilitiesOptimized(
            accessibleAssetIds = accessibleAssetIds,
            isAdmin = isAdmin,
            severity = severity,
            system = system,
            exceptionStatus = effectiveExceptionStatus,
            product = product,
            adDomain = adDomain,
            cloudAccountId = cloudAccountId,
            page = pageNumber,
            size = pageSize,
            sort = sort,
            sortDir = sortDir,
            knownTotal = knownTotal
        )

        log.info("Returning {} current vulnerabilities for user {} (page {}/{}, total {})",
            response.content.size, authentication.name, response.currentPage + 1, response.totalPages, response.totalElements)
        HttpResponse.ok(response)

    } catch (e: Exception) {
        log.error("Error fetching current vulnerabilities for user: {}", authentication.name, e)
        HttpResponse.serverError()
    }
}

// ==================== Export Job Endpoints ====================
// Feature: Vulnerability Export Performance Optimization - Background Job Pattern
//
// Workflow:
// 1. POST /api/vulnerabilities/export - Start export job (returns job ID)
// 2. GET /api/vulnerabilities/export/{jobId}/status - Poll for progress
// 3. GET /api/vulnerabilities/export/{jobId}/download - Download completed file
//
// Benefits:
// - No HTTP timeout issues (returns immediately)
// - Progress tracking for user feedback
// - Rate limiting (max 1 per user, 3 global)
// - Cancellation support
// - File cleanup after 24h

/**
 * Start a vulnerability export job
 *
 * POST /api/vulnerabilities/export
 * Auth: ADMIN, VULN, or SECCHAMPION role
 * Response: StartExportResponse with job ID
 *
 * The export runs in the background. Use the status endpoint to track progress
 * and the download endpoint to retrieve the file when complete.
 */
@Post("/api/vulnerabilities/export")
@Secured("ADMIN", "VULN", "SECCHAMPION")
open fun startExport(authentication: Authentication): HttpResponse<*> {
    return try {
        log.info("Starting vulnerability export job for user: {}", authentication.name)

        val jobDto = exportJobService.startExport(authentication)

        log.info("Export job created: {} for user {}", jobDto.jobId, authentication.name)
        HttpResponse.status<StartExportResponse>(HttpStatus.ACCEPTED)
            .body(StartExportResponse(
                jobId = jobDto.jobId,
                message = "Export job started. Poll the status endpoint for progress.",
                status = jobDto.status
            ))

    } catch (e: IllegalStateException) {
        log.warn("Export rate limit exceeded for user {}: {}", authentication.name, e.message)
        HttpResponse.status<ErrorResponse>(HttpStatus.TOO_MANY_REQUESTS)
            .body(ErrorResponse(e.message ?: "Rate limit exceeded"))
    } catch (e: Exception) {
        log.error("Error starting export job for user: {}", authentication.name, e)
        HttpResponse.serverError<ErrorResponse>()
            .body(ErrorResponse("An internal error occurred"))
    }
}

/**
 * Get export job status
 *
 * GET /api/vulnerabilities/export/{jobId}/status
 * Auth: ADMIN, VULN, or SECCHAMPION role
 * Response: ExportJobDto with progress information
 *
 * Poll this endpoint to track export progress.
 * Frontend should poll every 2 seconds while job is running.
 */
@Get("/api/vulnerabilities/export/{jobId}/status")
@Secured("ADMIN", "VULN", "SECCHAMPION")
open fun getExportStatus(
    jobId: String,
    authentication: Authentication
): HttpResponse<*> {
    return try {
        val jobDto = exportJobService.getJobStatus(jobId, authentication.name)

        if (jobDto == null) {
            log.warn("Export job not found: {} for user {}", jobId, authentication.name)
            return HttpResponse.notFound(ErrorResponse("Export job not found"))
        }

        HttpResponse.ok(jobDto)

    } catch (e: Exception) {
        log.error("Error getting export status for job: {}", jobId, e)
        HttpResponse.serverError<ErrorResponse>()
            .body(ErrorResponse("An internal error occurred"))

